CREATE DATABASE IF NOT EXISTS macecup CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE macecup;
CREATE TABLE IF NOT EXISTS players (uuid CHAR(36) PRIMARY KEY, username VARCHAR(16) NOT NULL, first_seen TIMESTAMP DEFAULT CURRENT_TIMESTAMP, last_seen TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, rank_name VARCHAR(32) DEFAULT 'default');
CREATE TABLE IF NOT EXISTS stats (uuid CHAR(36) PRIMARY KEY, wins INT DEFAULT 0, solo_wins INT DEFAULT 0, duo_wins INT DEFAULT 0, kills INT DEFAULT 0, deaths INT DEFAULT 0, rating INT DEFAULT 1000, highest_slam DOUBLE DEFAULT 0, heads INT DEFAULT 0, totem_pops INT DEFAULT 0, event_entries INT DEFAULT 0, cashcup_points INT DEFAULT 0);
CREATE TABLE IF NOT EXISTS cosmetics (uuid CHAR(36), cosmetic_key VARCHAR(96), unlocked BOOLEAN DEFAULT TRUE, selected BOOLEAN DEFAULT FALSE, PRIMARY KEY(uuid, cosmetic_key));
CREATE TABLE IF NOT EXISTS custom_emotes (id BIGINT AUTO_INCREMENT PRIMARY KEY, uuid CHAR(36), name VARCHAR(64) NOT NULL, body VARCHAR(160) NOT NULL, approved BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY(uuid, name));
CREATE TABLE IF NOT EXISTS purge_pity (uuid CHAR(36) PRIMARY KEY, pity_steps INT DEFAULT 0, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS resourcepack_status (uuid CHAR(36) PRIMARY KEY, status VARCHAR(32), sha1 CHAR(40), updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS event_history (id BIGINT AUTO_INCREMENT PRIMARY KEY, mode VARCHAR(32), arena VARCHAR(64), server_name VARCHAR(32), started_at TIMESTAMP NULL, ended_at TIMESTAMP NULL, winner_uuid CHAR(36));
CREATE TABLE IF NOT EXISTS cashcup_points (uuid CHAR(36), season VARCHAR(32), points INT DEFAULT 0, PRIMARY KEY(uuid, season));
CREATE TABLE IF NOT EXISTS parties (party_id CHAR(36), uuid CHAR(36), leader BOOLEAN DEFAULT FALSE, PRIMARY KEY(party_id, uuid));
CREATE TABLE IF NOT EXISTS punishments (id BIGINT AUTO_INCREMENT PRIMARY KEY, uuid CHAR(36), staff_uuid CHAR(36), type VARCHAR(32), reason VARCHAR(255), expires_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS leaderboard_cache (board_key VARCHAR(64), row_index INT, uuid CHAR(36), value_num DOUBLE, label VARCHAR(64), updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY(board_key, row_index));
CREATE TABLE IF NOT EXISTS arena_snapshots (id BIGINT AUTO_INCREMENT PRIMARY KEY, arena VARCHAR(64), server_name VARCHAR(32), world_name VARCHAR(64), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, mode VARCHAR(32));
CREATE TABLE IF NOT EXISTS arena_snapshot_blocks (snapshot_id BIGINT, x INT, y INT, z INT, block_data TEXT, tile_json MEDIUMTEXT, PRIMARY KEY(snapshot_id, x, y, z));
CREATE TABLE IF NOT EXISTS arena_snapshot_entities (snapshot_id BIGINT, entity_uuid CHAR(36), entity_type VARCHAR(64), entity_json MEDIUMTEXT, PRIMARY KEY(snapshot_id, entity_uuid));
